import sys
import functools

def main():
    import sys
    sys.setrecursionlimit(1000000)
    N, A, X, Y = map(int, sys.stdin.read().split())

    @functools.lru_cache(maxsize=None)
    def dp(n):
        if n == 0:
            return 0.0
        # Option 1: Pay X yen to divide by A
        cost1 = X + dp(n // A)
        # Option 2: Pay Y yen to roll the die
        cost2 = Y
        for b in range(1, 7):
            cost2 += dp(n // b) / 6.0
        return min(cost1, cost2)

    result = dp(N)
    print("{0:.15f}".format(result))

if __name__ == "__main__":
    main()
